// Compliant - lower complexity by extracting methods
class DataProcessor {
public:
    int processData(int type, int value, bool flag) {
        switch (type) {
            case 1: return processType1(value, flag);
            case 2: return processType2(value, flag);
            default: return processDefault(value);
        }
    }

private:
    int processType1(int value, bool flag) {
        if (value > 100) {
            return flag ? value * 2 : value + 10;
        }
        return value > 50 ? value + 5 : value;
    }

    int processType2(int value, bool flag) {
        return (flag && value > 0) ? value * 3 : 0;
    }

    int processDefault(int value) {
        const int multiplier = 10;
        return (value >= 1 && value <= 3) ? value * multiplier : -1;
    }
};
